import UIKit

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        if let userActivity = connectionOptions.userActivities.first {
            handleUniversalLink(userActivity)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUniversalLink(userActivity)
    }
    
    private func handleUniversalLink(_ userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else { return }
        
        processPromoLink(url)
    }
    
    private func processPromoLink(_ url: URL) {
        guard url.host == "myapp.com" && url.path == "/promo" else { return }
        
        let promoCode = url.getQueryParameter("code")
        let discount = url.getQueryParameter("discount")
        
        if let code = promoCode, let discountValue = Int(discount ?? "0") {
            applyPromoCodeToAccount(code: code, discount: discountValue)
        }
    }
    
    private func applyPromoCodeToAccount(code: String, discount: Int) {
        // Simulate applying promo code to user account
        print("Applying promo code: \(code) with discount: \(discount)%")
        
        // Here you would typically:
        // 1. Save the promo code to user's account
        // 2. Apply discount to user's purchases
        // 3. Update UI to show discount applied
        // 4. Send success notification to backend
        
        DispatchQueue.main.async {
            // Show success alert or update UI
            let alert = UIAlertController(title: "Promo Applied", message: "Discount of \(discount)% applied using code \(code)", preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            
            if let rootViewController = self.window?.rootViewController {
                rootViewController.present(alert, animated: true)
            }
        }
    }
}

extension URL {
    func getQueryParameter(_ parameter: String) -> String? {
        guard let url = URLComponents(string: self.absoluteString) else { return nil }
        return url.queryItems?.first { $0.name == parameter }?.value
    }
}